import{_ as l}from"./plugin-vue_export-helper-c27b6911.js";import{r as o,o as d,c as s,b as r,a as e,e as a,w as i,d as n}from"./app-75fed8c6.js";const p={},c=e("h2",{id:"spritematerial",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#spritematerial","aria-hidden":"true"},"#"),a(" SpriteMaterial")],-1),u=e("p",null,"一种使用Sprite的材质。",-1),f=n('<h2 id="构造器" tabindex="-1"><a class="header-anchor" href="#构造器" aria-hidden="true">#</a> 构造器</h2><h3 id="parameters-object" tabindex="-1"><a class="header-anchor" href="#parameters-object" aria-hidden="true">#</a> parameters : Object</h3><p>parameters - (可选)用于定义材质外观的对象，具有一个或多个属性。材质的任何属性都可以从此处传入(包括从Material继承的任何属性)</p><p>属性color例外，其可以作为十六进制字符串传递，默认情况下为 0xffffff（白色）， 内部调用Color.set(color)。 SpriteMaterials不会被Material.clippingPlanes裁剪。</p><h2 id="属性" tabindex="-1"><a class="header-anchor" href="#属性" aria-hidden="true">#</a> 属性</h2>',5),m=n('<h3 id="alphamap-texture" tabindex="-1"><a class="header-anchor" href="#alphamap-texture" aria-hidden="true">#</a> .alphaMap : Texture</h3><p>alpha贴图是一张灰度纹理，用于控制整个表面的不透明度。（黑色：完全透明；白色：完全不透明）。 默认值为null。</p><p>仅使用纹理的颜色，忽略alpha通道（如果存在）。 对于RGB和RGBA纹理，WebGL渲染器在采样此纹理时将使用绿色通道， 因为在DXT压缩和未压缩RGB 565格式中为绿色提供了额外的精度。 Luminance-only以及luminance/alpha纹理也仍然有效。</p><h3 id="color-color" tabindex="-1"><a class="header-anchor" href="#color-color" aria-hidden="true">#</a> .color : Color</h3><p>材质的颜色(Color)，默认值为白色 (0xffffff)。 .map会和 color 相乘。</p><h3 id="fog-boolean" tabindex="-1"><a class="header-anchor" href="#fog-boolean" aria-hidden="true">#</a> .fog : Boolean</h3><p>材质是否受雾影响。默认为true。</p><h3 id="isspritematerial-boolean" tabindex="-1"><a class="header-anchor" href="#isspritematerial-boolean" aria-hidden="true">#</a> .isSpriteMaterial : Boolean</h3><p>Read-only标志，用于检查给定对象是否为SpriteMaterial类型。</p><h3 id="map-texture" tabindex="-1"><a class="header-anchor" href="#map-texture" aria-hidden="true">#</a> .map : Texture</h3><p>颜色贴图。可以选择包括一个alpha通道，通常与.transparent 或.alphaTest。默认为null。</p><h3 id="rotation-radians" tabindex="-1"><a class="header-anchor" href="#rotation-radians" aria-hidden="true">#</a> .rotation : Radians</h3><p>sprite的转动，以弧度为单位。默认值为0。</p><h3 id="sizeattenuation-boolean" tabindex="-1"><a class="header-anchor" href="#sizeattenuation-boolean" aria-hidden="true">#</a> .sizeAttenuation : Boolean</h3><p>精灵的大小是否会被相机深度衰减。（仅限透视摄像头。）默认为true。</p><h3 id="transparent-boolean" tabindex="-1"><a class="header-anchor" href="#transparent-boolean" aria-hidden="true">#</a> .transparent : Boolean</h3><p>定义此材质是否透明。默认值为 true。</p><h2 id="方法" tabindex="-1"><a class="header-anchor" href="#方法" aria-hidden="true">#</a> 方法</h2>',18);function _(x,b){const h=o("IFrame"),t=o("RouterLink");return d(),s("div",null,[c,u,r(h,{url:"https://luotainxu-demo.netlify.app/#/threejs/material/spriteMaterial"}),f,e("p",null,[a("共有属性请参见其基类"),r(t,{to:"/threejs/%E6%9D%90%E8%B4%A8/%E6%9D%90%E8%B4%A8.html"},{default:i(()=>[a("Material")]),_:1})]),m,e("p",null,[a("共有方法请参见其基类"),r(t,{to:"/threejs/%E6%9D%90%E8%B4%A8/%E6%9D%90%E8%B4%A8.html"},{default:i(()=>[a("Material")]),_:1})])])}const E=l(p,[["render",_],["__file","点精灵材质.html.vue"]]);export{E as default};
